+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lines = text.split('\
');
+    const startIndex = lines.findIndex((line) => tocStart.test(line));
+    if (startIndex === -1) {
+      return text;
+    }
+
+    const endOffset = lines.slice(startIndex + 1).findIndex((line) => tocEnd.test(line));
+    const endIndex = endOffset === -1 ? -1 : startIndex + 1 + endOffset;
+    const regionEnd = endIndex === -1 ? startIndex : endIndex;
+    const headings = this.getHeadings(lines, startIndex, regionEnd, options);
+    const tocLines = this.buildToc(lines[startIndex], endIndex === -1 ? '<!-- /toc -->' : lines[endIndex], headings, options);
+
+    if (endIndex === -1) {
+      // A missing end marker should not consume the rest of the document.
+      lines.splice(startIndex, 1, ...tocLines);
+    } else {
+      lines.splice(startIndex, endIndex - startIndex + 1, ...tocLines);
+    }
+
+    return lines.join('\
');
+  }
+
+  private getHeadings(lines: string[], tocStartIndex: number, tocEndIndex: number, options: AutoTocOptions): Heading[] {
+    const anchors = new Map<string, number>();
+    const headings: Heading[] = [];
+    for (let index = 0; index < lines.length; index++) {
+      if (index > tocStartIndex && index < tocEndIndex) {
+        continue;
+      }
+
+      const match = lines[index].match(atxHeading);
+      if (!match) {
+        continue;
+      }
+
+      const level = match[2].length;
+      if (level < options.minLevel || level > options.maxLevel) {
+        continue;
+      }
+
+      const rawText = removeTrailingHeadingMarkers(match[3]);
+      const displayText = removeExplicitId(rawText).trim();
+      if (isExcluded(displayText, options.excludeHeadings)) {
+        continue;
+      }
+
+      const explicitId = options.useExplicitIds ? getExplicitId(rawText) : undefined;
+      const baseAnchor = explicitId ?? makeAnchor(displayText);
+      const count = anchors.get(baseAnchor) ?? 0;
+      anchors.set(baseAnchor, count + 1);
+      const anchor = count === 0 ? baseAnchor : `${baseAnchor}-${count}`;
+      headings.push({level, text: options.stripFormattingInToc ? stripFormatting(displayText) : removeImages(displayText).trim(), anchor});
+    }
+    return headings;
+  }
+
+  private buildToc(startMarker: string, endMarker: string, headings: Heading[], options: AutoTocOptions): string[] {
+    const result = [startMarker, ''];
+    if (options.title !== '') {
+      result.push(options.title, '');
+    }
+
+    for (let index = 0; index < headings.length; index++) {
+      const heading = headings[index];
+      const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
+      const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+      result.push(`${indent}${marker} [${heading.text}](#${heading.anchor})`);
+    }
+
+    result.push('', endMarker, '');
+    return result;
+  }
