+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.strip-formatting-in-toc.name', descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description', optionsKey: 'stripFormattingInToc'}),
+      new TextAreaOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.exclude-headings.name', descriptionKey: 'rules.auto-toc.exclude-headings.description', optionsKey: 'excludeHeadings'}),
+    ];
+  }
+}
+
+function removeTrailingHeadingMarkers(text: string): string {
+  return text.replace(/[ \	]+#+[ \	]*$/, '').trim();
+}
+
+function getExplicitId(text: string): string | undefined {
+  return text.match(/\\s+\\{#([^}\\s]+)\\}\\s*$/)?.[1];
+}
+
+function removeExplicitId(text: string): string {
+  return text.replace(/\\s+\\{#[^}\\s]+\\}\\s*$/, '');
+}
+
+function removeImages(text: string): string {
+  return text.replace(/!\\[\\[[^\\]]*\\]\\]/g, '').replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '');
+}
+
+function resolveLinks(text: string): string {
+  return text
+      .replace(/!?\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_match, target: string, display?: string) => display ?? target)
+      .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return resolveLinks(removeImages(text))
+      .replace(/`([^`]*)`/g, '$1')
+      .replace(/(\\*\\*|__)(.*?)\\1/g, '$2')
+      .replace(/(\\*|_)(.*?)\\1/g, '$2')
+      .replace(/~~(.*?)~~/g, '$1')
+      .replace(/\\\\([\\\\`*{}\\[\\]()#+.!_-])/g, '$1')
+      .trim();
+}
+
+function makeAnchor(text: string): string {
+  return stripFormatting(text).toLowerCase().replace(/\\s+/g, '-').replace(/[^a-z0-9-_]/g, '').replace(/-+/g, '-').replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(text: string, exclusions: string[]): boolean {
+  const comparable = stripFormatting(text);
+  return exclusions.some((entry) => {
+    const regex = entry.match(/^\\/(.*)\\/$/);
+    if (regex) {
+      try {
+        return new RegExp(regex[1], 'i').test(comparable);
+      } catch (_) {
+        return false;
+      }
+    }
+    return entry.toLowerCase() === comparable.toLowerCase();
+  });
+}
